def gen(rng, size):
    n = max(1, min(size, 2000))
    values = [rng.randint(1, 2000) for _ in range(n)]
    arr = [values[0]]
    alive = [True]
    idx = 1
    i = 0
    while i < len(alive) and idx < n:
        if alive[i]:
            for _ in range(2):
                if idx < n and rng.random() < 0.7:
                    arr.append(values[idx])
                    alive.append(True)
                    idx += 1
                else:
                    arr.append(None)
                    alive.append(False)
        i += 1
    k = rng.randint(1, 1024)
    return [arr, k]

