class Solution:
    def kthLargestPerfectSubtree(self, root, k):
        def height(node):
            if node is None:
                return 0
            return 1 + max(height(node.left), height(node.right))

        def count(node):
            if node is None:
                return 0
            return 1 + count(node.left) + count(node.right)

        def is_perfect(node):
            if node is None:
                return True
            h = height(node)
            c = count(node)
            return c == (1 << h) - 1

        sizes = []

        def collect(node):
            if node is None:
                return
            if is_perfect(node):
                sizes.append(count(node))
            collect(node.left)
            collect(node.right)

        collect(root)
        sizes.sort(reverse=True)
        return sizes[k - 1] if k <= len(sizes) else -1

