class Solution:
    def kthLargestPerfectSubtree(self, root, k):
        sizes = []

        def dfs(node):
            if node is None:
                return (0, True)
            ld, lp = dfs(node.left)
            rd, rp = dfs(node.right)
            if lp and rp and ld == rd:
                d = ld + 1
                size = (1 << d) - 1
                sizes.append(size)
                return (d, True)
            return (0, False)

        dfs(root)
        sizes.sort(reverse=True)
        return sizes[k - 1] if k <= len(sizes) else -1

