var kthLargestPerfectSubtree = function(root, k) {
    const sizes = [];
    function dfs(node) {
        if (node === null) return [0, true];
        const [ld, lp] = dfs(node.left);
        const [rd, rp] = dfs(node.right);
        if (lp && rp && ld === rd) {
            const d = ld + 1;
            const size = (1 << d) - 1;
            sizes.push(size);
            return [d, true];
        }
        return [0, false];
    }
    dfs(root);
    sizes.sort((a, b) => b - a);
    return k <= sizes.length ? sizes[k - 1] : -1;
};
